```class Solution {
public:
    int minMovesToMakePalindrome(string s) {
        int n = s.length();
        for (int i = 0; i < n / 2; i++) {
            if (s[i] != s[n - i - 1]) {
                swap(s[i], s[n - i - 1]);
            }
        }
        return n;
    }
};
